 153 | function base64ToText(str: string) {
 154 |     try {
 155 |         const binString = atob(str.replace(/\s/g, ''));
 156 |         const bytes = Uint8Array.from(binString, (m) => m.codePointAt(0)!);
 157 |         const decoded = new TextDecoder().decode(bytes);
 158 |         return decodeURIComponent(decoded);
 159 |     } catch (e) {
 160 |         try { return atob(str); } catch(e2) { return ""; }
 161 |     }
 162 | }
