 164 | function textToBase64(str: string) {
 165 |     const bytes = new TextEncoder().encode(str);
 166 |     const binString = Array.from(bytes, (byte) => String.fromCharCode(byte)).join("");
 167 |     return btoa(binString);
 168 | }
