 275 | async function ensureBranchExists(repo: string) {
 276 |   // 1. Check if DEV_BRANCH already exists
 277 |   try { 
 278 |       await githubFetch(repo, `/branches/${DEV_BRANCH}`); 
 279 |       return; 
 280 |   } catch (e) { /* Branch doesn't exist, proceed to create it */ }
 281 | 
 282 |   let baseSha = "";
 283 |   
 284 |   // 2. Try to find existing 'main' or 'master'
 285 |   try {
 286 |       const main = await githubFetch(repo, `/git/ref/heads/${MAIN_BRANCH}`);
 287 |       baseSha = main.object.sha;
 288 |   } catch (e) {
 289 |       try {
 290 |           // Fallback: Check for 'master' just in case
 291 |           const master = await githubFetch(repo, `/git/ref/heads/master`);
 292 |           baseSha = master.object.sha;
 293 |       } catch (e2) {
 294 |           // 3. REPO IS EMPTY (No main, no master)
 295 |           // We must create the "Root Commit" by creating a README
 296 |           console.log("Repo appears empty. Initializing with README.md...");
 297 |           try {
 298 |               // Create README directly on MAIN to initialize the repo history
 299 |               await updateFile(repo, "README.md", "# Project Initialized by Conduit", "", MAIN_BRANCH, "Initial commit");
 300 |               
 301 |               // Now that the commit exists, get its SHA
