 326 | async function genericRequestAI(role: keyof AIConfig['roles'], messages: any[], config?: AIConfig, tools?: any[], responseFormat?: any): Promise<any> {
 327 |   const provider = resolveProvider(role, config);
 328 |   if (!provider) throw new Error(`No provider found for role: ${role}`);
 329 | 
 330 |   // AI Trace Summary (Lightweight)
 331 |   console.log(`[AI_CALL] Role: ${role} | Provider: ${provider.name} | Model: ${provider.model}`);
 332 | 
 333 |   // 2. Persistent DB Log
 334 |   // We use a try-catch to ensure logging failure doesn't block the actual AI request
 335 |   try {
 336 |       await supabase.from('conduit_logs').insert({
 337 |           repo_name: 'DEBUG_TRACE', // Utility function doesn't know repo, using placeholder
 338 |           type: 'ai_prompt_dump',
 339 |           data: { 
 340 |               role, 
 341 |               provider: provider.name, 
 342 |               model: provider.model, 
 343 |               timestamp: new Date().toISOString(),
 344 |               messages_preview: messages 
 345 |           }
 346 |       });
 347 |   } catch (e) { console.error("Background log failed:", e); }
 348 |   
 349 |   // Advanced Rotation Logic: Fetch Least-Recently-Used key from 'api_keys' table
 350 |   const serviceMap: Record<string, string> = { 
 351 |       'Deepseek_API': 'deepseek', 
 352 |       'GEMINI_API_KEY': 'gemini', 
 353 |       'GROQ_API_KEY': 'groq' 
 354 |   };
 355 |   const serviceName = serviceMap[provider.apiKeyEnv];
 356 |   let apiKey = "";
 357 | 
 358 |   if (serviceName) {
 359 |       const { data: keyRow } = await supabase
 360 |           .from('api_keys')
 361 |           .select('id, api_key')
 362 |           .eq('service', serviceName)
 363 |           .eq('is_active', true)
 364 |           .or(`cooldown_until.is.null,cooldown_until.lt.${new Date().toISOString()}`)
 365 |           .order('last_used_at', { ascending: true, nullsFirst: true })
 366 |           .limit(1)
 367 |           .maybeSingle();
 368 | 
 369 |       if (keyRow) {
 370 |           apiKey = keyRow.api_key;
 371 |           // Mark as used immediately to move it to the end of the rotation queue
 372 |           await supabase.from('api_keys').update({ last_used_at: new Date().toISOString() }).eq('id', keyRow.id);
 373 |       }
 374 |   }
 375 | 
 376 |   // Fallback to Env Var if no key found in DB or service not mapped
 377 |   if (!apiKey) {
 378 |       apiKey = Deno.env.get(provider.apiKeyEnv) || "";
 379 |       if (!apiKey) {
 380 |           if (provider.apiKeyEnv && provider.apiKeyEnv.length > 10) apiKey = provider.apiKeyEnv;
 381 |           else throw new Error(`Missing API Key: No active keys for '${serviceName || provider.apiKeyEnv}' in DB or Env`);
 382 |       }
 383 |   }
 384 | 
 385 |   // ADAPTER: Google Native
 386 |   if (provider.type === 'google') {
 387 |     const promptText = messages.map(m => `[${m.role.toUpperCase()}]: ${m.content}`).join('\n');
 388 |           const url = `${provider.baseUrl}?key=${apiKey}`;
 389 |     
 390 |     const payload: any = { 
 391 |         contents: [{ parts: [{ text: promptText }] }]
 392 |     };
 393 | 
 394 |     // ADAPTER: Google Strict Function Calling
 395 |     if (tools && tools.length > 0 && messages[0].content.includes('STRICT')) {
 396 |         payload.tool_config = {
 397 |             function_calling_config: {
 398 |                 mode: "ANY",
 399 |                 allowed_function_names: [tools[0].function.name]
 400 |             }
 401 |         };
 402 |     }
 403 | 
 404 |     // MAP OPENAI TOOLS TO GOOGLE FUNCTION DECLARATIONS
 405 |     if (tools && tools.length > 0) {
 406 |         const mapType = (t: any) => {
 407 |             // Flatten union types ["integer", "null"] -> "INTEGER"
 408 |             const rawType = Array.isArray(t) ? t[0] : t;
 409 |             if (rawType === "integer") return "INTEGER";
 410 |             if (rawType === "string") return "STRING";
 411 |             if (rawType === "boolean") return "BOOLEAN";
 412 |             if (rawType === "number") return "NUMBER";
 413 |             if (rawType === "object") return "OBJECT";
 414 |             if (rawType === "array") return "ARRAY";
 415 |             return "STRING"; // Fallback
 416 |         };
 417 | 
 418 |         const transformSchema = (schema: any): any => {
 419 |             const newSchema: any = { type: mapType(schema.type) };
 420 |             if (schema.properties) {
 421 |                 newSchema.properties = {};
 422 |                 for (const key in schema.properties) {
 423 |                     newSchema.properties[key] = transformSchema(schema.properties[key]);
 424 |                 }
 425 |             }
 426 |             if (schema.items) {
 427 |                 newSchema.items = transformSchema(schema.items);
 428 |             }
 429 |             if (schema.required) newSchema.required = schema.required;
 430 |             return newSchema;
 431 |         };
 432 | 
 433 |         payload.tools = [{
 434 |             function_declarations: tools.map((t: any) => ({
 435 |                 name: t.function.name,
 436 |                 description: t.function.description,
 437 |                 parameters: transformSchema(t.function.parameters)
 438 |             }))
 439 |         }];
 440 |     }
 441 |     
 442 |     const res = await fetch(url, { method: 'POST', headers: { 'Content-Type': 'application/json' }, body: JSON.stringify(payload) });
 443 |     const data = await res.json();
 444 |     
 445 |     if (data.error) throw new Error(`Google AI Error: ${data.error.message || JSON.stringify(data.error)}`);
 446 |     
 447 |     console.log(`\n=== [AI RESPONSE RECEIVED] Provider: ${provider.name} (Google) ===`);
 448 |     
 449 |     const parts = data.candidates?.[0]?.content?.parts || [];
 450 |     let combinedContent = "";
 451 |     let tool_calls: any[] = [];
 452 | 
 453 |     // Loop through all parts to catch both text and function calls
