 993 |         }
 994 | 
 995 |         const match = findBlockRobust(content, op.anchor);
 996 |         if (match) {
 997 |              const before = content.substring(0, match.start);
 998 |              const after = content.substring(match.start);
 999 |              return { newContent: before + op.content + "\n" + after, success: true, score: 90, message: "Robust anchor match" };
1000 |         }
1001 |         return { newContent: content, success: false, score: 0, message: "Anchor not found" };
1002 |       }
1003 | 
1004 |       case "replace_between_anchors":
1005 |         const s = content.indexOf(op.start_anchor), e = content.indexOf(op.end_anchor);
1006 |         if(s > -1 && e > -1 && e > s) {
1007 |              const pre = content.substring(0, s + op.start_anchor.length), post = content.substring(e);
