 914 | function applyOperation(content: string, op: any) {
 915 |   const lines = content.split("\n");
 916 |   
 917 |   // Helper to find line by trimmed content
 918 |   const getLineIndex = (anchor: string) => {
 919 |       const cleanAnchor = anchor.trim();
 920 |       return lines.findIndex(l => l.trim() === cleanAnchor);
 921 |   };
 922 | 
 923 |   try {
 924 |     // --- AI HEALING ---
 925 |     if (op.is_ai_fix) {
 926 |         if (op.ai_strategy === "range_replace" && op.start_line && op.end_line) {
 927 |             lines.splice(op.start_line - 1, (op.end_line - op.start_line) + 1, op.replace_with || op.content || "");
 928 |                         const shortMsg = op.explanation ? (op.explanation.substring(0, 150) + "...") : "AI Fixed";
 929 |             return { newContent: lines.join("\n"), success: true, score: 95, message: `Ã¢ÂÂ¨ AI: ${shortMsg}` };
 930 |         }
 931 | 
 932 |         if (op.ai_strategy === "line_insert" && op.anchor_line) {
 933 |             const idx = op.anchor_line - 1;
 934 |             const payload = op.replace_with || op.content || "";
 935 |             if (op.action === "insert_after") {
 936 |                 lines.splice(idx + 1, 0, payload);
 937 |             } else if (op.action === "insert_before") {
 938 |                 lines.splice(idx, 0, payload);
 939 |             } else {
 940 |                 lines[idx] = payload;
 941 |             }
 942 |             const shortMsg = op.explanation ? (op.explanation.substring(0, 150) + "...") : "AI Fixed";
 943 |             return { newContent: lines.join("\n"), success: true, score: 95, message: `Ã¢ÂÂ¨ AI: ${shortMsg}` };
 944 |         }
 945 |     }
 946 | 
 947 |     switch (op.action) {
 948 |       case "replace_block": {
 949 |         if (!op.find_block) return { newContent: content, success: false, score: 0, message: "Missing find_block" };
 950 |         
 951 |         // Strategy A: Exact Match
 952 |         if (content.includes(op.find_block)) {
 953 |             return { newContent: content.replace(op.find_block, op.replace_with || ""), success: true, score: 100, message: "Exact match" };
 954 |         }
 955 |         // Strategy B: Robust Match (Ignores whitespace/indentation)
 956 |         const match = findBlockRobust(content, op.find_block);
 957 |         if (match) {
 958 |             const before = content.substring(0, match.start);
 959 |             const after = content.substring(match.end);
 960 |             return { newContent: before + (op.replace_with || "") + after, success: true, score: 95, message: "Structure match" };
 961 |         }
 962 |         return { newContent: content, success: false, score: 0, message: "Block not found" };
 963 |       }
 964 | 
 965 |       case "insert_after": {
 966 |         // Strategy A: Exact Line
 967 |         let idx = lines.indexOf(op.anchor);
 968 |         // Strategy B: Trimmed Line
 969 |         if (idx === -1) idx = getLineIndex(op.anchor);
 970 |         
 971 |         if (idx !== -1) {
 972 |             lines.splice(idx + 1, 0, op.content);
 973 |             return { newContent: lines.join("\n"), success: true, score: 100, message: "Inserted after line" };
 974 |         }
 975 |         
 976 |         // Strategy C: Robust Block Anchor
 977 |         const match = findBlockRobust(content, op.anchor);
 978 |         if (match) {
 979 |              const before = content.substring(0, match.end);
 980 |              const after = content.substring(match.end);
 981 |              return { newContent: before + "\n" + op.content + after, success: true, score: 90, message: "Robust anchor match" };
 982 |         }
 983 |         return { newContent: content, success: false, score: 0, message: "Anchor not found" };
 984 |       }
 985 | 
 986 |       case "insert_before": {
 987 |         let idx = lines.indexOf(op.anchor);
 988 |         if (idx === -1) idx = getLineIndex(op.anchor);
 989 | 
 990 |         if (idx !== -1) {
 991 |             lines.splice(idx, 0, op.content);
 992 |             return { newContent: lines.join("\n"), success: true, score: 100, message: "Inserted before line" };
 993 |         }
 994 | 
 995 |         const match = findBlockRobust(content, op.anchor);
 996 |         if (match) {
 997 |              const before = content.substring(0, match.start);
 998 |              const after = content.substring(match.start);
 999 |              return { newContent: before + op.content + "\n" + after, success: true, score: 90, message: "Robust anchor match" };
1000 |         }
1001 |         return { newContent: content, success: false, score: 0, message: "Anchor not found" };
1002 |       }
1003 | 
1004 |       case "replace_between_anchors":
1005 |         const s = content.indexOf(op.start_anchor), e = content.indexOf(op.end_anchor);
