1009 |         }
1010 |         return { newContent: content, success: false, score: 0, message: "Anchors not found" };
1011 | 
1012 |       case "create_file": 
1013 |         return { newContent: op.content || "", success: true, score: 100, message: "Created" };
1014 | 
1015 |       case "delete_file":
1016 |          return { newContent: "", success: true, score: 100, message: "Deleted" };
1017 | 
1018 |       default: 
1019 |         return { newContent: content, success: false, score: 0, message: "Unknown action" };
1020 |     }
1021 |   } catch(e:any) { 
