5177 |     function timeAgo(dateString) {
5178 |         const date = new Date(dateString);
5179 |         const now = new Date();
5180 |         const seconds = Math.floor((now - date) / 1000);
5181 |         if (seconds < 10) return 'just now';
5182 |         if (seconds < 60) return seconds + 's ago';
5183 |         const minutes = Math.floor(seconds / 60);
5184 |         if (minutes < 60) return minutes + 'm ago';
5185 |         const hours = Math.floor(minutes / 60);
5186 |         if (hours < 24) return hours + 'h ago';
5187 |         return date.toLocaleDateString();
5188 |     }
