5432 |             if (retryCount < MAX_RETRIES && loadMoreFn) {
5433 |                 console.log(`[DeepJump] Not found. Triggering loadMore (Attempt ${retryCount + 1})...`);
5434 |                 retryCount++;
5435 |                 showGlobalToast("ð Searching deeper...");
5436 |                 
5437 |                 await loadMoreFn(); 
5438 |                 await new Promise(r => setTimeout(r, 800)); // Wait for render
5439 |                 return attemptNavigation();
