1997 |     function smartJSONParse(jsonString) {
1998 |         try {
1999 |             return JSON.parse(jsonString);
2000 |         } catch (e) {
2001 |             console.warn("Standard JSON parse failed, attempting Robust Auto-Fix...");
2002 |             let fixed = jsonString
2003 |                 // 1. Fix backslashes that aren't part of a valid escape sequence
2004 |                 .replace(/\\(?!["\\/bfnrtu])/g, "\\\\")
2005 |                 // 2. Fix literal newlines inside strings (replace with \n)
2006 |                 .replace(/(\n)/g, (match, p1, offset) => {
2007 |                     // Only replace if we are likely inside a quoted string
2008 |                     const before = jsonString.slice(0, offset);
2009 |                     const quoteCount = (before.match(/"/g) || []).length;
2010 |                     return (quoteCount % 2 === 1) ? "\\n" : "\n";
2011 |                 });
2012 | 
2013 |             try {
2014 |                 const cleanObj = JSON.parse(fixed);
2015 |                 document.getElementById('json-input').value = fixed;
2016 |                 if (typeof saveState === 'function') saveState();
2017 |                 showGlobalToast("â¨ Robust Auto-Correction Applied");
2018 |                 return cleanObj;
2019 |             } catch (e2) {
2020 |                 console.error("Robust fix failed:", e2);
2021 |                 throw e; // Throw original error for better debugging
2022 |             }
2023 |         }
2024 |     }
