2026 |     function b64DecodeUnicode(str) {
2027 |         return decodeURIComponent(atob(str).split('').map(function(c) {
2028 |             return '%' + ('00' + c.charCodeAt(0).toString(16)).slice(-2);
2029 |         }).join(''));
