2033 |     function b64EncodeUnicode(str) {
2034 |         return btoa(encodeURIComponent(str).replace(/%([0-9A-F]{2})/g,
2035 |             function toSolidBytes(match, p1) { return String.fromCharCode('0x' + p1); }));
2036 |     }
