2038 |     function base64ToUint8Array(base64) {
2039 |         const binaryString = atob(base64);
2040 |         const bytes = new Uint8Array(binaryString.length);
2041 |         for (let i = 0; i < binaryString.length; i++) {
2042 |             bytes[i] = binaryString.charCodeAt(i);
