2053 |     function resolvePath(base, relative) {
2054 |         const stack = base.split('/');
2055 |         stack.pop(); 
2056 |         const parts = relative.split('/');
2057 |         for (let i = 0; i < parts.length; i++) {
2058 |             if (parts[i] === '.') continue;
2059 |             if (parts[i] === '..') stack.pop();
2060 |             else stack.push(parts[i]);
2061 |         }
2062 |         return stack.join('/');
2063 |     }
