2338 |     async function runAutoFixLoop(name, code, errorList) {
2339 |         const status = document.getElementById('ef-status-msg');
2340 |         let currentCode = code;
2341 |         let currentErrors = errorList;
2342 | 
2343 |         // Fix one by one (recursive loop)
2344 |         async function fixNext(index) {
2345 |             if (index >= currentErrors.length) return true; // All initial errors processed
2346 | 
2347 |             const err = currentErrors[index];
2348 |             status.innerText = `ð§ Fixing Error ${index + 1}/${currentErrors.length} (Line ${err.line})...`;
2349 |             status.style.color = "#eab308"; // Dev yellow
2350 | 
2351 |             try {
2352 |                 // 1. Get Patch from AI
2353 |                 const res = await fetch(CONFIG.funcUrl, { 
2354 |                     method: 'POST', 
2355 |                     headers: {'Content-Type': 'application/json'},
2356 |                     body: apiBody({ 
2357 |                         action: 'propose_syntax_fix', 
2358 |                         code: currentCode, 
2359 |                         error: err 
2360 |                     })
2361 |                 });
2362 |                 const data = await res.json();
2363 |                 const ops = data.operations;
2364 | 
2365 |                 if (!ops || ops === "[]") throw new Error("AI could not generate a fix.");
2366 | 
2367 |                 // 2. Apply Patch Locally
2368 |                 const patchResult = applyLocalPatch(currentCode, ops);
2369 |                 if (!patchResult.success) throw new Error("Generated patch did not match code.");
2370 | 
2371 |                 currentCode = patchResult.content;
2372 |                 document.getElementById('ef-code').value = currentCode; // Update UI
2373 | 
2374 |                 // 3. Re-Validate
2375 |                 const scanRes = await fetch(CONFIG.funcUrl, { 
2376 |                     method: 'POST', headers: {'Content-Type': 'application/json'},
2377 |                     body: apiBody({ action: 'validate_syntax_deep', code_block: currentCode, file_path: 'index.ts' })
2378 |                 });
2379 |                 const scanData = await scanRes.json();
2380 | 
2381 |                 if (scanData.valid) {
2382 |                     status.innerText = "â Syntax Fixed!";
2383 |                     return true;
2384 |                 } else {
2385 |                     // If errors remain, update list and Prompt user
2386 |                     currentErrors = scanData.errors;
2387 |                     if (confirm(`Fix applied, but ${currentErrors.length} errors remain. Continue fixing?`)) {
2388 |                         // Recursively fix the *new* first error (since layout changed)
2389 |                         return await fixNext(0);
2390 |                     } else {
2391 |                         return false;
2392 |                     }
2393 |                 }
2394 | 
2395 |             } catch (e) {
2396 |                 if (confirm(`Auto-Fix Failed: ${e.message}\n\nTry again?`)) {
2397 |                     return await fixNext(index);
2398 |                 } else {
2399 |                     return false;
2400 |                 }
2401 |             }
2402 |         }
2403 | 
2404 |         return await fixNext(0);
2405 |     }
