5168 |     // --- GENERIC UI ---
5169 |     function formatBytes(bytes) {
5170 |         if (!bytes) return '0 B';
5171 |         const k = 1024;
5172 |         const sizes = ['B', 'KB', 'MB', 'GB'];
5173 |         const i = Math.floor(Math.log(bytes) / Math.log(k));
5174 |         return parseFloat((bytes / Math.pow(k, i)).toFixed(1)) + ' ' + sizes[i];
5175 |     }
