5390 |     async function jumpToElement(selector, tabId, navIndex, loadMoreFn) {
5391 |         console.group(`[DeepJump] Target: ${selector} in ${tabId}`);
5392 |         
5393 |         const navItems = document.querySelectorAll('.nav-item');
5394 |         switchTab(tabId, navItems[navIndex]);
5395 | 
5396 |         const scrollContainer = document.querySelector('.main-view');
5397 |         let retryCount = 0;
5398 |         const MAX_RETRIES = 5;
5399 | 
5400 |         const attemptNavigation = async () => {
5401 |             const element = document.querySelector(selector);
5402 |             
5403 |             if (element) {
5404 |                 console.log("[DeepJump] Element found. Scrolling...");
5405 |                 
5406 |                 // Wait for any tab transition animations
5407 |                 await new Promise(r => setTimeout(r, 300));
5408 | 
5409 |                 let offsetTop = 0;
5410 |                 let curr = element;
5411 |                 while (curr && curr !== scrollContainer) {
5412 |                     offsetTop += curr.offsetTop;
5413 |                     curr = curr.offsetParent;
5414 |                 }
5415 | 
5416 |                 const targetScroll = offsetTop - (scrollContainer.clientHeight / 2) + (element.clientHeight / 2);
5417 |                 scrollContainer.scrollTo({ top: targetScroll, behavior: 'smooth' });
5418 | 
5419 |                 // Visual Highlight
5420 |                 element.style.transition = 'all 0.5s ease';
5421 |                 element.style.backgroundColor = 'rgba(59, 130, 246, 0.3)';
