7045 |         // dbHistory is sorted newest -> oldest
7046 |         let oldestSelectedIndex = -1;
7047 |         checkboxes.forEach(cb => {
7048 |             const idx = dbHistory.findIndex(h => String(h.id) === String(cb.value));
7049 |             if (idx > oldestSelectedIndex) oldestSelectedIndex = idx;
7050 |         });
7051 | 
7052 |         // The target is the first record older than our selection that isn't also being deleted
7053 |         let rollbackTarget = null;
7054 |         for (let i = oldestSelectedIndex + 1; i < dbHistory.length; i++) {
