5168 |     function formatBytes(bytes) {
5169 |         if (!bytes) return '0 B';
5170 |         const k = 1024;
5171 |         const sizes = ['B', 'KB', 'MB', 'GB'];
5172 |         const i = Math.floor(Math.log(bytes) / Math.log(k));
5173 |         return parseFloat((bytes / Math.pow(k, i)).toFixed(1)) + ' ' + sizes[i];
5174 |     }
