5176 |     function timeAgo(dateString) {
5177 |         const date = new Date(dateString);
5178 |         const now = new Date();
5179 |         const seconds = Math.floor((now - date) / 1000);
5180 |         if (seconds < 10) return 'just now';
5181 |         if (seconds < 60) return seconds + 's ago';
5182 |         const minutes = Math.floor(seconds / 60);
5183 |         if (minutes < 60) return minutes + 'm ago';
5184 |         const hours = Math.floor(minutes / 60);
5185 |         if (hours < 24) return hours + 'h ago';
5186 |         return date.toLocaleDateString();
5187 |     }
