5389 |     async function jumpToElement(selector, tabId, navIndex, loadMoreFn) {
5390 |         console.group(`[DeepJump] Target: ${selector} in ${tabId}`);
5391 |         
5392 |         const navItems = document.querySelectorAll('.nav-item');
5393 |         switchTab(tabId, navItems[navIndex]);
5394 | 
5395 |         const scrollContainer = document.querySelector('.main-view');
5396 |         let retryCount = 0;
5397 |         const MAX_RETRIES = 5;
5398 | 
5399 |         const attemptNavigation = async () => {
5400 |             const element = document.querySelector(selector);
5401 |             
5402 |             if (element) {
5403 |                 console.log("[DeepJump] Element found. Scrolling...");
5404 |                 
5405 |                 // Wait for any tab transition animations
5406 |                 await new Promise(r => setTimeout(r, 300));
5407 | 
5408 |                 let offsetTop = 0;
5409 |                 let curr = element;
5410 |                 while (curr && curr !== scrollContainer) {
5411 |                     offsetTop += curr.offsetTop;
5412 |                     curr = curr.offsetParent;
5413 |                 }
5414 | 
5415 |                 const targetScroll = offsetTop - (scrollContainer.clientHeight / 2) + (element.clientHeight / 2);
5416 |                 scrollContainer.scrollTo({ top: targetScroll, behavior: 'smooth' });
5417 | 
5418 |                 // Visual Highlight
5419 |                 element.style.transition = 'all 0.5s ease';
5420 |                 element.style.backgroundColor = 'rgba(59, 130, 246, 0.3)';
5421 |                 element.style.boxShadow = '0 0 30px rgba(59, 130, 246, 0.6)';
5422 |                 setTimeout(() => {
5423 |                     element.style.backgroundColor = '';
5424 |                     element.style.boxShadow = '';
5425 |                 }, 3000);
5426 |                 
5427 |                 console.groupEnd();
5428 |                 return true;
5429 |             }
5430 | 
5431 |             if (retryCount < MAX_RETRIES && loadMoreFn) {
5432 |                 console.log(`[DeepJump] Not found. Triggering loadMore (Attempt ${retryCount + 1})...`);
5433 |                 retryCount++;
5434 |                 showGlobalToast("ð Searching deeper...");
5435 |                 
5436 |                 await loadMoreFn(); 
5437 |                 await new Promise(r => setTimeout(r, 800)); // Wait for render
5438 |                 return attemptNavigation();
5439 |             }
5440 | 
5441 |             console.error("[DeepJump] Failed: Element not found after retries.");
5442 |             showGlobalToast("Entry not found in recent history.", true);
5443 |             console.groupEnd();
5444 |             return false;
5445 |         };
5446 | 
5447 |         setTimeout(attemptNavigation, 100);
5448 |     }
