7037 |     async function deleteSelectedHistory() {
7038 |         const checkboxes = Array.from(document.querySelectorAll('.history-check:checked'));
7039 |         if (!checkboxes.length) return;
7040 | 
7041 |         const idsToDelete = checkboxes.map(cb => cb.value);
7042 |         
7043 |         // Find the oldest record among the selection to determine rollback target
7044 |         // dbHistory is sorted newest -> oldest
7045 |         let oldestSelectedIndex = -1;
7046 |         checkboxes.forEach(cb => {
7047 |             const idx = dbHistory.findIndex(h => String(h.id) === String(cb.value));
7048 |             if (idx > oldestSelectedIndex) oldestSelectedIndex = idx;
7049 |         });
7050 | 
7051 |         // The target is the first record older than our selection that isn't also being deleted
7052 |         let rollbackTarget = null;
7053 |         for (let i = oldestSelectedIndex + 1; i < dbHistory.length; i++) {
7054 |             if (!idsToDelete.includes(String(dbHistory[i].id))) {
7055 |                 rollbackTarget = dbHistory[i];
7056 |                 break;
7057 |             }
7058 |         }
7059 | 
7060 |         let msg = `Delete ${checkboxes.length} selected records?`;
7061 |         if (rollbackTarget) {
7062 |             msg += `\n\nâ ï¸ This will ROLLBACK your GitHub repository to: "${rollbackTarget.title}"`;
7063 |         }
7064 | 
7065 |         if (!confirm(msg)) return;
7066 | 
7067 |         showGlobalToast("Batch Deleting & Rolling back...");
7068 | 
7069 |         // 1. Perform Rollback
7070 |         if (rollbackTarget) {
7071 |             await fetch(CONFIG.funcUrl, {
7072 |                 method: 'POST', headers: {'Content-Type': 'application/json'},
7073 |                 body: apiBody({ action: 'rollback', ref_sha: rollbackTarget.sha })
