2280 |                 // Strategy 2: Line-by-Line Fuzzy Match (Whitespace Agnostic)
2281 |                 const searchLines = op.find_block.split('\n').map(l => l.trim()).filter(l => l !== '');
2282 |                 if (searchLines.length === 0) return;
2283 | 
2284 |                 let matchStart = -1;
2285 |                 let matchEnd = -1;
2286 | 
2287 |                 // Scan file lines
2288 |                 for (let i = 0; i < lines.length; i++) {
2289 |                     // If first line matches (ignoring whitespace)
2290 |                     if (lines[i].trim() === searchLines[0]) {
2291 |                         // Check subsequent lines
2292 |                         let allMatch = true;
2293 |                         let fileOffset = 0;
2294 |                         let searchOffset = 1;
2295 |                         
2296 |                         while (searchOffset < searchLines.length) {
2297 |                             if (i + fileOffset + 1 >= lines.length) { allMatch = false; break; }
2298 |                             const nextFile = lines[i + fileOffset + 1].trim();
2299 |                             // Skip empty lines in file if they aren't in search block
2300 |                             if (nextFile === '') {
2301 |                                 fileOffset++;
2302 |                                 continue;
2303 |                             }
2304 |                             if (nextFile !== searchLines[searchOffset]) {
2305 |                                 allMatch = false;
2306 |                                 break;
2307 |                             }
2308 |                             fileOffset++;
2309 |                             searchOffset++;
2310 |                         }
2311 | 
2312 |                         if (allMatch) {
2313 |                             matchStart = i;
2314 |                             matchEnd = i + fileOffset;
2315 |                             break;
2316 |                         }
2317 |                     }
2318 |                 }
2319 | 
2320 |                 if (matchStart !== -1) {
2321 |                     // Replace the range of lines
2322 |                     const replacement = op.replace_with.split('\n');
2323 |                     lines.splice(matchStart, (matchEnd - matchStart) + 1, ...replacement);
2324 |                     logs.push(`Fuzzy match applied (Lines ${matchStart+1}-${matchEnd+1})`);
2325 |                 } else {
2326 |                     success = false;
2327 |                     logs.push(`Failed to find block: "${op.find_block.substring(0, 30)}..."`);
2328 |                     console.warn("Patch Mismatch. File has:", content.substring(0, 200), "... vs Search:", op.find_block);
2329 |                 }
2330 |             }
2331 |         });
2332 |         return { content: lines.join('\n'), success, logs };
2333 |     }
