5394 | 
5395 |         const scrollContainer = document.querySelector('.main-view');
5396 |         let retryCount = 0;
5397 |         const MAX_RETRIES = 5;
5398 | 
5399 |         const attemptNavigation = async () => {
5400 |             const element = document.querySelector(selector);
5401 |             
5402 |             if (element) {
5403 |                 console.log("[DeepJump] Element found. Scrolling...");
5404 |                 
5405 |                 // Wait for any tab transition animations
5406 |                 await new Promise(r => setTimeout(r, 300));
5407 | 
5408 |                 let offsetTop = 0;
5409 |                 let curr = element;
5410 |                 while (curr && curr !== scrollContainer) {
5411 |                     offsetTop += curr.offsetTop;
5412 |                     curr = curr.offsetParent;
5413 |                 }
5414 | 
5415 |                 const targetScroll = offsetTop - (scrollContainer.clientHeight / 2) + (element.clientHeight / 2);
5416 |                 scrollContainer.scrollTo({ top: targetScroll, behavior: 'smooth' });
5417 | 
5418 |                 // Visual Highlight
5419 |                 element.style.transition = 'all 0.5s ease';
5420 |                 element.style.backgroundColor = 'rgba(59, 130, 246, 0.3)';
