6564 |                         const path = cleanChunk.substring(0, firstLineEnd).trim();
6565 |                         const content = cleanChunk.substring(firstLineEnd + 1);
6566 |                         if (path) pendingImportFiles.push({ path, content });
6567 |                     }
6568 |                 });
6569 |             } 
6570 |             else {
6571 |                 throw new Error("Unsupported file format. Use .zip or .txt exported from Conduit.");
6572 |             }
