7865 |     function extractTableNames(sql) {
7866 |         if (!sql) return [];
7867 |         const tables = [];
7868 |         const systemNoise = ['columns', 'tables', 'schemata', 'information_schema'];
7869 |         
7870 |         // Pattern 1: Standard FROM/JOIN (handles schema.table and "table")
7871 |         const fromRegex = /(?:FROM|JOIN)\s+(?:(?:"?\w+"?\.)?"?(\w+)"?)/gi;
7872 |         // Pattern 2: Metadata queries (WHERE table_name = '...')
7873 |         const metaRegex = /table_name\s*=\s*'([^']+)'/gi;
7874 | 
7875 |         let match;
7876 |         while ((match = fromRegex.exec(sql)) !== null) {
7877 |             const name = match[1];
7878 |             if (name && !tables.includes(name) && !systemNoise.includes(name.toLowerCase())) {
7879 |                 tables.push(name);
7880 |             }
7881 |         }
7882 |         
7883 |         while ((match = metaRegex.exec(sql)) !== null) {
7884 |             const name = match[1];
7885 |             if (name && !tables.includes(name) && !systemNoise.includes(name.toLowerCase())) {
7886 |                 tables.push(name);
7887 |             }
7888 |         }
7889 | 
7890 |         return tables;
7891 |     }
7892 | 
7893 |     function convertToCSV(resultObj) {
7894 |         const data = resultObj.data || [];
7895 |         if (!data.length) return '';
7896 |         
7897 |         const tables = extractTableNames(resultObj.sql);
7898 |         const metaHeader = tables.length > 0 ? `# Source Tables: ${tables.join(', ')}\n# Export Date: ${new Date().toISOString()}\n` : '';
7899 | 
7900 |         const headers = Object.keys(data[0]);
7901 |         const rows = data.map(row => 
7902 |             headers.map(header => {
7903 |                 let cell = row[header] === null || row[header] === undefined ? '' : row[header];
7904 |                 if (typeof cell === 'object') cell = JSON.stringify(cell);
7905 |                 return '"' + String(cell).replace(/"/g, '""') + '"';
7906 |             }).join(',')
7907 |         );
7908 |         return metaHeader + [headers.join(','), ...rows].join('\n');
7909 |     }
