5167 |     function formatBytes(bytes) {
5168 |         if (!bytes) return '0 B';
5169 |         const k = 1024;
5170 |         const sizes = ['B', 'KB', 'MB', 'GB'];
5171 |         const i = Math.floor(Math.log(bytes) / Math.log(k));
5172 |         return parseFloat((bytes / Math.pow(k, i)).toFixed(1)) + ' ' + sizes[i];
5173 |     }
