5175 |     function timeAgo(dateString) {
5176 |         const date = new Date(dateString);
5177 |         const now = new Date();
5178 |         const seconds = Math.floor((now - date) / 1000);
5179 |         if (seconds < 10) return 'just now';
5180 |         if (seconds < 60) return seconds + 's ago';
5181 |         const minutes = Math.floor(seconds / 60);
5182 |         if (minutes < 60) return minutes + 'm ago';
5183 |         const hours = Math.floor(minutes / 60);
5184 |         if (hours < 24) return hours + 'h ago';
5185 |         return date.toLocaleDateString();
5186 |     }
