6890 |                 // 1. Try Exact Match
6891 |                 let startIdx = fullText.indexOf(searchText);
6892 |                 
6893 |                 // 2. Try Robust Match (Ignoring Line Endings differences)
6894 |                 if (startIdx === -1) {
6895 |                     const clean = (s) => s.replace(/\r\n/g, '\n').trim();
6896 |                     startIdx = clean(fullText).indexOf(clean(searchText));
6897 |                 }
6898 | 
6899 |                 if (startIdx !== -1) {
6900 |                     const linesBefore = fullText.substring(0, startIdx).split('\n');
6901 |                     const startRow = linesBefore.length - 1;
6902 |                     const startCol = linesBefore[startRow].length;
6903 |                     const linesInSearch = searchText.split('\n');
6904 |                     const endRow = startRow + linesInSearch.length - 1;
6905 |                     const endCol = linesInSearch.length > 1 ? linesInSearch[linesInSearch.length - 1].length : startCol + searchText.length;
6906 |                     return new Range(startRow, startCol, endRow, endCol);
6907 |                 }
6908 |                 return null;
6909 |             };
6910 |             
6911 |             const searchRemove = data.op.find_block || data.op.anchor;
